import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-cv-view',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './cv-view.component.html',
  styleUrls: ['./cv-view.component.css']
})
export class CvViewComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  cvData = { title: '', summary: '', skills: '', interests: '', experiences: [] as any[], educations: [] as any[] };
  candidateName: string = '';
  avatarUrl: string | null = null;
  candidateContact = { email: '', phone: '', address: '' };
  isLoading: boolean = true;

  ngOnInit() {
    this.candidateName = localStorage.getItem('name') || 'Candidat';
    this.fetchProfileDetailsAndCV();
  }

  fetchProfileDetailsAndCV() {
    const token = localStorage.getItem('token');
    
    const profilePromise = fetch('http://localhost:3000/api/candidate/profile/details', {
      method: 'GET', headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    }).then(res => res.ok ? res.json() : null);

    const cvPromise = fetch('http://localhost:3000/api/candidate/cv/details', {
      method: 'GET', headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    }).then(res => res.ok ? res.json() : null);

    Promise.all([profilePromise, cvPromise])
      .then(([profileData, cvDetails]) => {
        
        // 1. Extraction des informations de l'utilisateur
        if (profileData) {
          const user = Array.isArray(profileData) ? profileData[0] : profileData;
          if (user) {
            this.candidateContact.email = user.email || '';
            this.candidateContact.phone = user.phone || '';
            this.candidateContact.address = user.address || '';
            this.candidateName = user.name || this.candidateName;
            if (user.avatar_logo) {
              this.avatarUrl = `http://localhost:3000/logos/${user.avatar_logo}`;
            }
          }
        }
        
        // 2. Extraction du CV avec double sécurité sur les index MySQL
        if (cvDetails) {
          let cv = cvDetails;
          
          // 🚀 FORCE L'EXTRACTION DE L'INDEX ZERO SI LE BACKEND RENVOIE UN TABLEAU
          if (Array.isArray(cvDetails)) {
            cv = cvDetails[0];
          }
          if (cv && Array.isArray(cv)) {
            cv = cv[0];
          }

          if (cv && (cv.title || cv.summary)) {
            this.cvData.title = cv.title || '';
            this.cvData.summary = cv.summary || '';
            this.cvData.skills = cv.skills || '';
            this.cvData.interests = cv.interests || '';
            
            try {
              this.cvData.experiences = typeof cv.experience === 'string' ? JSON.parse(cv.experience) : (cv.experience || []);
            } catch { this.cvData.experiences = []; }

            try {
              this.cvData.educations = typeof cv.education === 'string' ? JSON.parse(cv.education) : (cv.education || []);
            } catch { this.cvData.educations = []; }
          }
        }

        this.isLoading = false;
        this.cdr.detectChanges();
      })
      .catch(err => {
        console.error("Erreur de synchronisation globale CV :", err);
        this.isLoading = false;
        this.cdr.detectChanges();
      });
  }

  getSkillsArray(): string[] { return this.cvData.skills ? this.cvData.skills.split(',').filter(s => s.trim() !== '') : []; }
  getInterestsArray(): string[] { return this.cvData.interests ? this.cvData.interests.split(',').filter(i => i.trim() !== '') : []; }
}
<div class="cv-view-container">

  <!-- En-tête avec action d'impression -->
  <div class="cv-view-header-flex">
    <div class="header-left-text">
      <h3>
        <i class="bi bi-eye-fill" style="color: #0ea5e9;"></i>
        Rendu de mon CV Public
      </h3>
      <p>
        Mise en page finale de votre dossier telle qu'elle sera visualisée
        par les recruteurs tunisiens.
      </p>
    </div>

    <button class="btn-print-cv" onclick="window.print()">
      <i class="bi bi-printer-fill"></i>
      Exporter en PDF / Imprimer
    </button>
  </div>

  <!-- ⏳ ÉTAT DE CHARGEMENT -->
  @if (isLoading) {
    <div class="cv-view-loading">
      <i class="bi bi-arrow-clockwise animate-spin text-xl text-sky-500"></i>

      <p
        style="
          margin-top: 8px;
          color: #64748b;
          font-weight: 500;
        "
      >
        Génération de votre CV public...
      </p>
    </div>
  }

  <!-- 🚫 CV VIDE -->
  @if (!isLoading && !cvData.title) {
    <div class="cv-view-empty-card">
      <i
        class="bi bi-file-earmark-person-fill"
        style="
          font-size: 32px;
          color: #cbd5e1;
          display: block;
          margin-bottom: 8px;
        "
      ></i>

      <h4>Votre CV en ligne est vide</h4>

      <p>
        Veuillez vous rendre sur l'onglet
        <strong>« Construire mon CV »</strong>
        pour renseigner vos compétences et vos expériences professionnelles.
      </p>
    </div>
  }

  <!-- 🚀 AFFICHAGE FINAL -->
  @if (!isLoading && cvData.title) {

    <div class="cv-view-grid-layout">

      <!-- CARD 1 -->
      <div class="cv-view-panel-card">

        <h4 class="panel-box-title">
          <i class="bi bi-person-bounding-box"></i>
          Identité & Résumé
        </h4>

        <!-- HEADER PROFIL -->
        <div class="view-profile-header">

          <div class="view-avatar-wrapper">
            @if (avatarUrl) {
              <img [src]="avatarUrl" alt="Photo Candidat">
            } @else {
              <i class="bi bi-person-fill"></i>
            }
          </div>

          <div class="view-meta-block">
            <h4>{{ candidateName }}</h4>

            <span class="view-job-subtitle">
              {{ cvData.title }}
            </span>
          </div>

        </div>

        <!-- CONTACT -->
        <div class="view-contact-grid">

          <div class="view-contact-item">
            <i class="bi bi-envelope-fill"></i>
            {{ candidateContact.email }}
          </div>

          <div class="view-contact-item">
            <i class="bi bi-telephone-fill"></i>
            {{ candidateContact.phone || 'Non renseigné' }}
          </div>

          <div class="view-contact-item span-full-view">
            <i class="bi bi-geo-alt-fill"></i>
            {{ candidateContact.address || 'Non renseignée' }}
          </div>

        </div>

        <!-- RÉSUMÉ -->
        <div class="view-resume-box">
          <strong>Résumé professionnel :</strong>

          <p>
            {{ cvData.summary || 'Aucune description rédigée.' }}
          </p>
        </div>

      </div>

      <!-- CARD 2 -->
      <div class="cv-view-panel-card">

        <h4 class="panel-box-title">
          <i class="bi bi-file-earmark-text-fill"></i>
          Détails Professionnels
        </h4>

        <!-- EXPÉRIENCES -->
        <div class="view-section-item">

          <span class="view-section-label">
            <i class="bi bi-briefcase-fill"></i>
            Expériences Professionnelles
          </span>

          @if (cvData.experiences.length > 0) {

            @for (exp of cvData.experiences; track $index) {

              <div class="view-block-pro">

                <div class="view-row-pro">
                  <strong>{{ exp.job_title }}</strong>

                  <span class="view-date-tag">
                    {{ exp.duration }}
                  </span>
                </div>

                <span class="view-sub-title">
                  🏢 {{ exp.company }}
                </span>

                <p class="view-desc-text">
                  {{ exp.description }}
                </p>

              </div>

            }

          } @else {

            <span class="view-empty-text-italic">
              Aucune expérience répertoriée.
            </span>

          }

        </div>

        <!-- FORMATIONS -->
        <div class="view-section-item" style="margin-top: 20px;">

          <span class="view-section-label">
            <i class="bi bi-mortarboard-fill"></i>
            Formations & Études
          </span>

          @if (cvData.educations.length > 0) {

            @for (edu of cvData.educations; track $index) {

              <div class="view-block-pro">

                <div class="view-row-pro">

                  <strong>{{ edu.degree }}</strong>

                  <span class="view-date-tag">
                    {{ edu.year }}
                  </span>

                </div>

                <span class="view-sub-title">
                  🎓 {{ edu.school }}
                </span>

              </div>

            }

          } @else {

            <span class="view-empty-text-italic">
              Aucune formation académique répertoriée.
            </span>

          }

        </div>

        <!-- COMPÉTENCES -->
        <div class="view-section-item" style="margin-top: 20px;">

          <span class="view-section-label">
            <i class="bi bi-star-fill"></i>
            Compétences Clés
          </span>

          <div class="view-tags-container">

            @if (cvData.skills) {

              @for (skill of getSkillsArray(); track skill) {

                <span class="view-skill-tag">
                  {{ skill.trim() }}
                </span>

              }

            } @else {

              <span class="view-empty-text-italic">
                Aucune compétence ajoutée.
              </span>

            }

          </div>

        </div>

        <!-- CENTRES D'INTÉRÊT -->
        <div class="view-section-item" style="margin-top: 20px;">

          <span class="view-section-label">
            <i class="bi bi-heart-fill"></i>
            Centres d'intérêt
          </span>

          <div class="view-tags-container">

            @if (cvData.interests) {

              @for (interest of getInterestsArray(); track interest) {

                <span class="view-interest-tag">
                  {{ interest.trim() }}
                </span>

              }

            } @else {

              <span class="view-empty-text-italic">
                Aucun centre d'intérêt ajouté.
              </span>

            }

          </div>

        </div>

      </div>

    </div>

  }

</div>
